customCss:
@import url('https://fonts.googleapis.com/css2?family=Bricolage+Grotesque:wght@400;500;600;700&family=Playfair+Display:wght@400;600;700;800&display=swap');
:root { --font-body: 'Bricolage Grotesque', sans-serif; --font-display: 'Playfair Display', serif; --radius: 10px; --ambient-glow-opacity: 0.22; --hero-backdrop-brightness: 0.55; --hero-backdrop-saturate: 1.4; --hero-text-shadow: 0 4px 30px rgba(255,100,0,0.4), 0 18px 50px rgba(0,0,0,0.6); }

/* Ember noise texture overlay */
body::after { content: ''; position: fixed; inset: 0; opacity: 0.03; background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E"); pointer-events: none; z-index: 9999; }

/* ═══════════════════════════════════════
   SIDEBAR — Wider, warm, cinematic panel
   ═══════════════════════════════════════ */
aside { width: 290px !important; border-right: 1px solid rgba(255,145,0,0.1) !important; background: linear-gradient(180deg, #0a0602 0%, #0e0904 50%, #0a0602 100%) !important; backdrop-filter: none !important; box-shadow: 4px 0 30px rgba(0,0,0,0.4); }
aside::after { content: ''; position: absolute; top: 0; right: 0; bottom: 0; width: 1px; background: linear-gradient(180deg, rgba(255,145,0,0.25), rgba(255,145,0,0.05) 40%, rgba(255,145,0,0.05) 60%, rgba(255,145,0,0.25)); pointer-events: none; }
@media (min-width: 1024px) { main#main-content:not([class*='ml-16']) { margin-left: 290px !important; } }

.sidebar-logo-icon { background: linear-gradient(135deg, rgba(255,145,0,0.2), rgba(255,204,0,0.1)) !important; border: 1px solid rgba(255,145,0,0.3) !important; box-shadow: 0 4px 16px rgba(255,100,0,0.15); border-radius: 10px !important; }
.sidebar-logo-text { font-family: 'Playfair Display', serif !important; font-weight: 700 !important; letter-spacing: 0.02em !important; font-size: 1.1rem !important; }

/* Nav items: serif, warm */
.sidebar-nav-item { font-family: 'Bricolage Grotesque', sans-serif; font-weight: 500; border-radius: 10px !important; }
.sidebar-nav-item span { font-family: 'Bricolage Grotesque', sans-serif; }

/* Warm section dividers */
.sidebar-libraries, .sidebar-personal { border-top: 1px solid rgba(255,145,0,0.06); padding-top: 0.75rem; margin-top: 0.5rem; }
.sidebar-footer { border-top: 1px solid rgba(255,145,0,0.1) !important; }

/* ═══════════════════════════════════════
   HERO — Taller, more dramatic
   ═══════════════════════════════════════ */
.home-hero { min-height: 80dvh !important; border-bottom: 1px solid rgba(255,145,0,0.08) !important; }
@media (min-width: 1024px) { .home-hero { min-height: 85dvh !important; } }

/* Warm vignette overlay on hero */
.home-hero::after { content: ''; position: absolute; inset: 0; background: radial-gradient(ellipse at center, transparent 40%, rgba(16,10,4,0.3) 100%); pointer-events: none; z-index: 4; }

/* Hero title: dramatic serif */
.home-hero h1 { font-family: 'Playfair Display', serif !important; font-weight: 800 !important; font-style: italic; }

/* Detail hero: taller, cinematic */
.item-detail-hero { border-bottom: 1px solid rgba(255,145,0,0.08) !important; }
.item-detail-hero h1 { font-family: 'Playfair Display', serif !important; font-weight: 800 !important; font-style: italic; }

/* ═══════════════════════════════════════
   CARDS — Warm glow, cinematic shadows
   ═══════════════════════════════════════ */
.media-card-image { border: 1px solid rgba(255,145,0,0.08) !important; box-shadow: 0 4px 16px rgba(60,30,0,0.3), 0 1px 4px rgba(0,0,0,0.3) !important; transition: all 0.4s ease !important; }
.media-card:hover .media-card-image { border-color: rgba(255,145,0,0.25) !important; box-shadow: 0 12px 35px rgba(255,100,0,0.2), 0 4px 12px rgba(60,30,0,0.3) !important; }
.media-card:hover { transform: translateY(-5px) scale(1.02) !important; }

/* ═══════════════════════════════════════
   SECTION ROWS — Serif headers
   ═══════════════════════════════════════ */
.section-row h2 { font-family: 'Playfair Display', serif !important; font-weight: 600 !important; font-size: 1.2rem !important; letter-spacing: 0.01em !important; font-style: italic; }
.section-row h2 span { font-style: normal; font-family: 'Bricolage Grotesque', sans-serif; font-weight: 500; }

/* ═══════════════════════════════════════
   DETAIL PAGE — Cinematic presentation
   ═══════════════════════════════════════ */
.page-title { font-family: 'Playfair Display', serif !important; font-weight: 800 !important; font-style: italic; }
.page-shell h2 { font-family: 'Playfair Display', serif; font-weight: 600; font-size: 1.15rem; font-style: italic; }

/* Larger poster on detail pages */
.item-detail-hero .media-card-image { box-shadow: 0 8px 30px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,145,0,0.1) !important; }

/* ═══════════════════════════════════════
   BADGES, BUTTONS & UI
   ═══════════════════════════════════════ */
.metadata-badge { border: 1px solid rgba(255,145,0,0.12) !important; background: rgba(255,145,0,0.05) !important; font-family: 'Bricolage Grotesque', sans-serif; }
.pill-primary { background: linear-gradient(135deg, #ff9100, #ffab40) !important; box-shadow: 0 4px 18px rgba(255,100,0,0.3); border: none !important; }
.pill-primary:hover { box-shadow: 0 8px 28px rgba(255,100,0,0.45) !important; transform: translateY(-1px); }
.pill-glass { border: 1px solid rgba(255,145,0,0.12) !important; }
.action-circle { border: 1px solid rgba(255,145,0,0.1); }

/* Tab bar: warm underline */
.tab-active { border-bottom: 2px solid #ff9100 !important; box-shadow: 0 2px 10px rgba(255,145,0,0.2); }

/* ═══════════════════════════════════════
   GLASS & SURFACES — Warm-tinted
   ═══════════════════════════════════════ */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(255,145,0,0.06) !important; box-shadow: 0 4px 16px rgba(60,30,0,0.2); }
.surface-panel { border: 1px solid rgba(255,145,0,0.06) !important; box-shadow: 0 4px 16px rgba(60,30,0,0.2); }

/* ═══════════════════════════════════════
   MOBILE HEADER — Warm cinematic
   ═══════════════════════════════════════ */
.mobile-header { border: 1px solid rgba(255,145,0,0.1) !important; box-shadow: 0 4px 16px rgba(60,30,0,0.25); }

/* ═══════════════════════════════════════
   AMBIENT & PROGRESS
   ═══════════════════════════════════════ */
@keyframes ember-pulse { 0%, 100% { opacity: 0.22; } 50% { opacity: 0.3; } }
.ambient-glow { animation: ember-pulse 5s ease-in-out infinite !important; }
.progress-fill { background: linear-gradient(90deg, #ff5722, #ff9100, #ffcc00) !important; box-shadow: 0 0 10px rgba(255,145,0,0.4); }

/* Carousel arrows: warm */
.home-hero button[class*='glass-subtle'] { border: 1px solid rgba(255,145,0,0.15) !important; }
